// 현재 시각 기반으로 기상청 API 파라미터 계산
const now = new Date();

// KST 변환
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);

const yyyymmdd = kst.toISOString().slice(0, 10).replace(/-/g, '');
let hh = kst.getUTCHours();
const mm = kst.getUTCMinutes();

// 초단기실황은 매시 40분에 발표 → 40분 이전이면 1시간 전 데이터 요청
if (mm < 40) hh = hh - 1;
if (hh < 0) hh = 23;

const baseTime = String(hh).padStart(2, '0') + '00';

return [{
  json: {
    baseDate: yyyymmdd,
    baseTime: baseTime,
    nx: 60,
    ny: 125
  }
}];

// 초단기실황 파싱
const items = $('기상청 초단기실황 API').item.json?.response?.body?.items?.item || [];
const fcstItems = $('초단기예보 (최고/최저기온)').item.json?.response?.body?.items?.item || [];

// category → value 맵 생성
const obs = {};
for (const item of items) {
  obs[item.category] = item.obsrValue;
}

// 예보에서 최고/최저기온 계산
const temps = fcstItems
  .filter(i => i.category === 'T1H')
  .map(i => parseFloat(i.fcstValue))
  .filter(v => !isNaN(v));

const tempHigh = temps.length ? Math.max(...temps) : null;
const tempLow  = temps.length ? Math.min(...temps) : null;

// SKY 코드 → 텍스트
const skyMap = { '1': '맑음', '3': '구름많음', '4': '흐림' };
// PTY 코드 → 텍스트
const ptyMap = { '0': '없음', '1': '비', '2': '비/눈', '3': '눈', '5': '빗방울', '6': '진눈깨비', '7': '눈날림' };
// 풍향 계산
const windDirDeg = parseFloat(obs['VEC'] || 0);
const dirs = ['N','NNE','NE','ENE','E','ESE','SE','SSE','S','SSW','SW','WSW','W','WNW','NW','NNW'];
const windDir = dirs[Math.round(windDirDeg / 22.5) % 16];

return [{
  json: {
    station:    '이천시 부발읍',
    nx:         60,
    ny:         125,
    temp:       parseFloat(obs['T1H'] || 0),
    temp_high:  tempHigh,
    temp_low:   tempLow,
    sky:        skyMap[obs['SKY']] || '맑음',
    humidity:   parseInt(obs['REH'] || 0),
    wind_dir:   windDir,
    wind_speed: parseFloat(obs['WSD'] || 0),
    pop:        0,
    pty:        ptyMap[obs['PTY']] || '없음',
    fetched_at: new Date().toISOString()
  }
}];

// 성공 로그
const data = $input.item.json;
console.log(`[WF-04] 날씨 수집 완료: ${data.temp}°C, ${data.sky}, 습도${data.humidity}%`);
return $input.all();
